Equation | Potential Cause 
-------- | ---------------
3x + 4y | Habitat loss 
5x - 2y | Overhunting 
2x + 3y | Disease 
7x - 3y | Climate change 
[Go code]
func solveEquation(equation string) string {
 //parse equation string to extract coefficients
 var xCoeff, yCoeff int
 fmt.Sscanf(equation, "%dx + %dy", &xCoeff, &yCoeff)

 //evaluate equation for x=2 and y=3
 result := (xCoeff*2) + (yCoeff*3)

 //determine if result matches a potential cause
 if result == 9 {
 return "Habitat loss"
 } else if result == 16 {
 return "Overhunting"
 } else if result == 13 {
 return "Disease"
 } else if result == 5 {
 return "Climate change"
 } else {
