func expandEquation(_ input: String) -> String? {
 let pattern = "((.*))((.*))" // regular expression pattern for matching the equation
 guard let regex = try? NSRegularExpression(pattern: pattern), let match = regex.firstMatch(in: input, range: NSRange(input.startIndex..., in: input)) else {
